  },
  size: {
    default: "h-9 px-4 py-2 has-[>svg]:px-3",
    xs: "h-7 rounded-md gap-1 px-2.5 text-xs has-[>svg]:px-2 [&_svg:not([class*=size-])]:size-3.5",
    sm: "h-8 rounded-lg gap-1.5 px-3 has-[>svg]:px-2.5",
    lg: "h-10 rounded-lg px-6 has-[>svg]:px-4",
